var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"멤버들의 행적이 외부로 드러나지 않도록 하라는 건가요?","JPN":"メンバーの動きが外にバレないようにする、ということでしょうか？","ENG":"You want me to keep the members' whereabouts from being revealed to the outside?","TWN":"你不想讓外界看到成員們的行蹤？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"맞아요. 그게 육익에서 당신이 맡게 될 일입니다.","JPN":"そうです。それが六翼で君が務めることになる仕事です。","ENG":"Yes. That will be your role in Six Wings.","TWN":"沒錯，這就是你在六翼中要做的事。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"각본을 꾸미는 당신의 재능에 가장 어울리는 역할이라고 판단했어요.","JPN":"脚本を作りあげる君の才能に最も相応しい役割だと判断しました。","ENG":"I believe it's the perfect role that matches your talents for devising scripts.","TWN":"我們認為這個職責非常適合你的劇本寫作才華。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"타인의 발자국을 지운다는 건 제가 그 발자국의 가장 가까운 곳에 있어야 한다는 뜻이죠.","JPN":"他人の足跡を消すということは、私がその足跡と一番近い場所に居なければならないということですね。","ENG":"Being able to erase another's footprints means that I have to be the closest to those footprints.","TWN":"要消除別人的腳印就表示我必須離他們非常近。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"<color=#ffd34c>외부인</color>인 저에게 그런 일을 맡기고 함부로 신뢰하는 건 비밀결사의 리더가 보일 법한 행동은 아니네요.","JPN":"<color=#ffd34c>部外者</color>である私にそのような仕事を任せ、むやみに信頼するとは、秘密組織のリーダーが取るべき行動とは思えませんね。","ENG":"And entrusting an <color=#ffd34c>outsider</color> to do that doesn't seem like something a leader of a secret organization should do.","TWN":"把這樣的任務託付給我這個<color=#ffd34c>外人</color>，似乎不像是一個秘密組織的首領會有的行為。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그렇기 때문에 이 세계의 많은 정보가 필요한 당신에겐 저의 제안을 거절할 이유가 없겠죠.","JPN":"だからこそ、この世界の情報を多く必要とする君は、僕の提案を断る理由がないはずです。","ENG":"You have no reason to decline this offer since you need all the information you can get about this world. ","TWN":"所以，對於需要盡可能多收集這個世界的情報的你來說，沒有理由拒絕我的提議。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신에게도 이곳에서 이루고 싶은 궁극의 목적이 있을 테니까요. 우리 육익은 개인의 목적을 존중하는 편이거든요.","JPN":"君にとってもここで成し遂げたい究極の目的があるはずですから。僕たち六翼は個人の目的を尊重していますよ。","ENG":"I'm sure you have something you wish to achieve here. And Six Wings respects everyone's individual goals.","TWN":"在這裡，你可能也有自己想要實現的終極目標，而我們六翼非常尊重成員的個人目的。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 개인의 목적이… 당신들을 등지게 만드는 빌미가 된다고 하더라도 말인가요?","JPN":"その個人の目的が……あなたたちを裏切ることになるとしてもですか？","ENG":"Even if that goal... could be used as an excuse to turn against you?","TWN":"即使那個人的目的……會讓你與她反目？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"어차피 우리의 이해관계가 합치하는 건, 첫번째 클리포트 게임이 승리로 끝날 때까지입니다.","JPN":"どうせ僕たちの利害関係が一致するのは、最初のクリフォトゲームで勝利するまで、ですから。","ENG":"Our interests will only align until the first Qliphoth Game is won.","TWN":"反正我們的合作關係會持續到在第一次逆卡巴拉遊戲勝利為止。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그 이후에도 우리와 함께 할 것인지는 당신의 선택에 맡기겠어요.","JPN":"その後も僕たちと行動を共にするかは、君の選択次第です。","ENG":"Afterwards, it's your choice whether you stay or leave us.","TWN":"至於在那以後要不要和我們一起行動，完全取決於你。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신의 육익이 가진 최종 목적은 뭐죠?","JPN":"あなたたち六翼の最終目的は何ですか？","ENG":"What's the real purpose of Six Wings?","TWN":"你的六翼的最終目標是什麼？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"세계평화.","JPN":"世界平和。","ENG":"World peace.","TWN":"世界和平。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"누가 보기에도 악의 축이나 다름없는 일들을 꾸미면서 말인가요?","JPN":"誰が見ても悪の組織のようなことを企んでいるのに、ですか？","ENG":"Even when you all are conspiring to do things that people expect an axis of evil to do?","TWN":"但你們做的明明是壞人才會做的事。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"맞습니다. 그렇기 때문에 스완, 당신이라면 이해할 거예요.","JPN":"そうです。だからこそスワン、君なら理解できるはずです。","ENG":"Correct. That's why I believe you'll understand it, Swan.","TWN":"沒錯，所以我相信你能理解我們，史旺。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그것의 정의를 온전히 지키는 것과, 그 정의를 비틀어서라도 지켜내는 것의 차이를요.","JPN":"正義を正しく守ることと、その正義をねじり曲げてでも守り通すことの違いを。","ENG":"The difference between those who strive to uphold justice in its entirety and those who protect it even if it means twisting the justice.","TWN":"忠實地守護其定義，與即使扭曲其定義也堅持守護之間的區別。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이걸로… 봉인의 마지막 단계만 남았어요.","JPN":"これで……封印は最後の段階だけ残っています。","ENG":"With this... only the last step of the seal remains.","TWN":"接下來……只剩下封印的最後一個步驟了。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지금쯤 배우들도 무대의 중심에 다다르고 있겠죠.","JPN":"今頃は役者たちも舞台の中心に来ているでしょう。","ENG":"The actors should be gathering at the main stage about now.","TWN":"此時，演員們應該快走到舞台中央了吧。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};